import React from 'react'
import styled from 'styled-components'

function Header() {
    return (
        <Nav>
            <Logo src="/images/logo.svg" />
        </Nav>
    )
}

export default Header

const Nav = styled.header`
    height: 48px;
    background: black;
`

const Logo = styled.img`
    display: flex;
`
